// Size-1 快取：同一則 user message 會被 routing/wiki/recall/skill/intent
// 各 embed 一次，快取上一次輸入即可讓後續呼叫免跑 ONNX forward。
// 向量對所有呼叫端都是唯讀（cosineSim / 序列化），共享實例安全。
let lastEmbedText: string | null = null;
let lastEmbedVec: Float32Array | null = null;

async function embed(text: string): Promise<Float32Array> {
  if (text === lastEmbedText && lastEmbedVec) return lastEmbedVec;
  // Strip chat-template special tokens that some models leak into output.
  // The BGE tokenizer rejects them, causing "Disallowed special token" errors.
  const clean = text.replace(/<\|[a-z_]+\|>/g, "");
  const output = await embedder!(clean, { pooling: "mean", normalize: true });
  const vec = output.data as Float32Array;
  lastEmbedText = text;
  lastEmbedVec = vec;
  return vec;
}

