  const files = readdirSync(TRACE_DIR)
    .filter((f) => f.startsWith("acp-trace-") && f.endsWith(".jsonl"))
    .map((f) => {
      const p = path.join(TRACE_DIR, f);
      return { p, mtime: statSync(p).mtimeMs };
    })
    .sort((a, b) => b.mtime - a.mtime);
  if (!files.length) throw new Error(`no trace files under ${TRACE_DIR}`);
  return files[0].p;
}

