import { appendFileSync, mkdirSync, readdirSync, statSync, unlinkSync } from "node:fs";
import path from "node:path";

const MEMORY_DIR = process.env.MEMORY_DIR || "F:\\AI\\AIMemory";
const TRACE_DIR = path.join(MEMORY_DIR, "acp-trace");
const MAX_RECENT = 200;
// 磁碟寫入預設關閉（ACP_TRACE=1 開啟）：每個 streaming chunk 一次同步
// appendFileSync 正好疊在熱路徑上，且 trace 檔無輪替會永久累積。
// 記憶體 buffer（readLast）不受 gate 影響，即時查詢照常。
const TRACE_TO_DISK = process.env.ACP_TRACE === "1";
const MAX_TRACE_AGE_MS = 7 * 24 * 60 * 60 * 1000;

// 一次性清理 7 天前的舊 trace 檔（無論 gate 開關，防既有累積變磁碟洩漏）
let cleanupDone = false;
function cleanupOldTraces(): void {
  if (cleanupDone) return;
  cleanupDone = true;
  try {
    const cutoff = Date.now() - MAX_TRACE_AGE_MS;
    for (const f of readdirSync(TRACE_DIR)) {
      if (!f.startsWith("acp-trace-") || !f.endsWith(".jsonl")) continue;
      const p = path.join(TRACE_DIR, f);
      try {
        if (statSync(p).mtimeMs < cutoff) unlinkSync(p);
      } catch {
        // 單檔失敗跳過
      }
    }
  } catch {
    // 目錄不存在等 — 無害
  }
}

