void (async () => {
  // model 先載（memory-recall / skill-router / wiki-retrieval 等模組只需要
  // model，不應被 NotebookLM routing table 的存在與否 gate 住）
  try {
    await initEmbedModel();
  } catch (err) {
    console.warn("[embed-router] model init failed:", err);
  }
  await Promise.allSettled([
    // Embedding-based NotebookLM router
    (async () => {
      try {
        const routingPath = resolveBridgeConfigPath("notebooklm-routing.json", detectAgentConfigDir());
        const raw = await readFile(routingPath, "utf8");
        const routing = JSON.parse(raw);
        if (routing.version === 2) {
          await initEmbedRouter(routing);
        } else {
          console.log("[embed-router] skipped: routing.json is not v2");
        }
      } catch (err: any) {
        if (err?.code === "ENOENT") {
          console.log("[embed-router] skipped: notebooklm-routing.json not found");
        } else {
          console.warn("[embed-router] init failed:", err);
        }
      }
    })(),
    // 補算 fact 嵌入 — vectorSearch 依賴 embedding_cache 有 fact 向量
    backfillFactEmbeddings()
      .then((n) => { if (n > 0) console.log(`[memory-db] backfilled ${n} fact embeddings`); })
      .catch((err) => console.warn("[memory-db] embedding backfill failed:", err)),
    // Memory recall (topic-based semantic retrieval)
    initMemoryRecall()
      .catch((err) => console.warn("[memory-recall] init failed:", err)),
    // Skill router (semantic skill matching)
    initSkillRouter()
      .catch((err) => console.warn("[skill-router] init failed:", err)),
    // MoA preset router (semantic preset matching)
    initMoaPresetRouter()
      .catch((err) => console.warn("[moa-router] init failed:", err)),
    // Wiki retrieval (semantic wiki page matching)
    initWikiRetrieval()
      .catch((err) => console.warn("[wiki-retrieval] init failed:", err)),
    // Index retrieval (PageIndex tree-based document matching)
    import("./index-retrieval.js")
      .then(({ initIndexRetrieval }) => initIndexRetrieval())
      .catch((err) => console.warn("[index-retrieval] init failed:", err)),
    // Intent classifier (natural language → /command matching)
    initIntentClassifier(COMMAND_SPECS.map((s) => ({ name: s.name, usage: s.usage, desc: s.desc })))
      .catch((err) => console.warn("[intent-classifier] init failed:", err)),
  ]);
  console.log("[startup] embedding init chain complete");
})();

