toolUseResult.originalFile:
/**
 * enrichment.ts — Shared dynamic enrichment logic (NotebookLM routing,
 * wiki retrieval, memory recall) used by both the main agent turn and
 * specialist proxy/delegation.
 */

import { isEmbedRouterReady, routeByEmbedding } from "./embed-router.js";
import { isWikiRetrievalReady, retrieveWikiPages, formatWikiBlock } from "./wiki-retrieval.js";
import { isMemoryRecallReady, recallRelevantFacts, formatRecallBlock } from "./memory-recall.js";
import { isIndexRetrievalReady, retrieveIndexChunks, formatIndexBlock } from "./index-retrieval.js";
import { logHit } from "./hit-log.js";
import { config } from "./config.js";

// ─── Types ─────────────────────────────────────────────────────────────────

/** Scope filter — limits enrichment to a specialist's domain. */
export interface EnrichmentScope {
  /** Only match these wiki page slugs. */
  wikiPages?: string[];
  /** Only match notebooks whose title is in this list. */
  notebooks?: string[];
  /** Only recall from these topic names. */
  topics?: string[];
}

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * Run the three enrichment stages and return a prefix string to prepend
 * to the user message. If `scope` is provided, results are filtered to
 * only the specified domain (for specialist use).
 */
export async function runEnrichment(
  userMsg: string,
  userId: number | string,
  recentFacts?: Set<string>,
  scope?: EnrichmentScope,
): Promise<string> {
  let prefix = "";

  // 1. NotebookLM routing
  if (isEmbedRouterReady()) {
    try {
      const titleFilter = scope?.notebooks?.length
        ? new Set(scope.notebooks)
        : undefined;
      const hits = await routeByEmbedding(userMsg, titleFilter);
      if (hits.length > 0) {
        const hitLines = hits.map(
          (h) => `- 《${h.title}》(id=${h.notebookId}, score=${h.score.toFixed(3)}, strategy=${h.strategy})`,
        );
        prefix +=
          `[NotebookLM routing — embedding match]\n` +
          `以下 notebook 與使用者問題語意相近，請用 notebook_query 查詢後以該 strategy 格式回答：\n` +
          hitLines.join("\n") +
          `\n[End routing]\n\n`;
      }
    } catch (err) {
      console.warn("[enrichment] notebooklm routing failed:", err);
    }
  }

  // 2. Wiki retrieval
  const wikiHitSlugs = new Set<string>();
  if (isWikiRetrievalReady()) {
    try {
      const slugFilter = scope?.wikiPages?.length
        ? new Set(scope.wikiPages)
        : undefined;
      const hits = await retrieveWikiPages(userMsg, slugFilter);
      // Dedup: skip wiki pages already injected in a prior turn
      const fresh = recentFacts
        ? hits.filter((h) => !recentFacts.has(`wiki:${h.slug}`))
        : hits;
      if (fresh.length > 0) {
        for (const h of fresh) {
          wikiHitSlugs.add(h.slug);
          recentFacts?.add(`wiki:${h.slug}`);
          logHit("wiki", h.slug, "wiki-retrieval");
        }
        prefix = formatWikiBlock(fresh) + prefix;
      }
    } catch (err) {
      console.warn("[enrichment] wiki retrieval failed:", err);
    }
  }

  // 3. Memory recall
  if (isMemoryRecallReady()) {
    try {
      const includeTopics = scope?.topics?.length
        ? new Set(scope.topics)
        : undefined;
      const hits = await recallRelevantFacts(
        userMsg, userId, recentFacts, wikiHitSlugs, includeTopics,
      );
      if (hits.length > 0) {
        // Track injected facts for cross-turn dedup
        if (recentFacts) {
          for (const h of hits) for (const f of h.facts) recentFacts.add(f);
        }
        for (const h of hits) logHit("fact", h.topic, "memory-recall");
        prefix = formatRecallBlock(hits) + prefix;
      }
    } catch (err) {
      console.warn("[enrichment] memory recall failed:", err);
    }
  }

  // 4. Index retrieval (PageIndex tree-based document chunks)
  if (isIndexRetrievalReady() && !scope) {
    try {
      const hits = await retrieveIndexChunks(userMsg);
      const fresh = recentFacts
        ? hits.filter((h) => !recentFacts.has(`idx:${h.slug}`))
        : hits;
      if (fresh.length > 0) {
        for (const h of fresh) {
          recentFacts?.add(`idx:${h.slug}`);
          logHit("index", h.slug, "index-retrieval");
        }
        prefix += formatIndexBlock(fresh);
      }
    } catch (err) {
      console.warn("[enrichment] index retrieval failed:", err);
    }
  }

  return applyPrefixCap(prefix);
}

// ─── Enrichment Prefix Cap ─────────────────────────────────────────────────

/**
 * Section markers used to identify removable blocks in priority order (lowest first).
 * When the enrichment prefix exceeds the character cap, sections are stripped
 * starting from the lowest-priority one until it fits.
 */
const SECTION_PRIORITY: Array<{ start: string; end: string; label: string }> = [
  { start: "[Document indexes", end: "[End indexes]", label: "index-retrieval" },
  { start: "[Memory recall", end: "[End memory recall]", label: "memory-recall" },
  { start: "[Wiki retrieval", end: "[End wiki retrieval]", label: "wiki-retrieval" },
  // NotebookLM routing and Skill routing are kept (short + high-value routing directives)
];

/**
 * If the prefix exceeds config.enrichmentPrefixMaxChars, strip lowest-priority
 * sections until it fits. Returns the (possibly trimmed) prefix.
 */
function applyPrefixCap(prefix: string): string {
  const cap = config.enrichmentPrefixMaxChars;
  if (prefix.length <= cap) return prefix;

  let result = prefix;
  for (const section of SECTION_PRIORITY) {
    if (result.length <= cap) break;

    const startIdx = result.indexOf(section.start);
    if (startIdx < 0) continue;
    const endIdx = result.indexOf(section.end, startIdx);
    if (endIdx < 0) continue;

    const removed = result.slice(startIdx, endIdx + section.end.length);
    result = result.slice(0, startIdx) + result.slice(endIdx + section.end.length);
    // Clean up leading/trailing newlines from removal
    result = result.replace(/\n{3,}/g, "\n\n");

    console.log(
      `[enrichment] prefix cap: stripped [${section.label}] (${removed.length} chars), ` +
      `remaining ${result.length}/${cap}`,
    );
  }

  // If still over cap after stripping all removable sections, hard-truncate
  if (result.length > cap) {
    console.warn(
      `[enrichment] prefix still over cap after stripping (${result.length}/${cap}), hard-truncating`,
    );
    result = result.slice(0, cap) + "\n[...enrichment truncated]\n";
  }

  return result;
}

