import { readFileSync } from "node:fs";
import path from "node:path";

const src = readFileSync(path.resolve("src/run-prompt.ts"), "utf8");

const finalRenderStart = src.indexOf("const suffix = stopHint + usageLine;");
if (finalRenderStart < 0) {
  throw new Error("final render suffix marker not found");
}

const relayBlockStart = src.indexOf("if (relayReplyTo) {", finalRenderStart);
if (relayBlockStart < 0) {
  throw new Error("relayReplyTo final-send block not found");
}

const relayBlockEnd = src.indexOf("if (!placeholder)", relayBlockStart);
if (relayBlockEnd < 0) {
  throw new Error("relayReplyTo block end marker not found");
}

const relayBlock = src.slice(relayBlockStart, relayBlockEnd);

if (!relayBlock.includes("const shouldSendAutoReply = !sentExplicitReply && full.trim() !== \"\";")) {
  throw new Error("relay auto reply should send non-empty closing text even when RELAY_DONE is present");
}

const relayDoneCheck = relayBlock.indexOf("RELAY_DONE");
const autoReplySend = relayBlock.indexOf("sendRelay(relayReplyTo, full)");
const autoReplyCondition = relayBlock.indexOf("const shouldSendAutoReply");
if (autoReplyCondition < 0 || autoReplyCondition > autoReplySend) {
  throw new Error("auto reply condition must be computed before sending");
}
if (relayDoneCheck < 0) {
  throw new Error("RELAY_DONE should still be logged in the final relay path");
}

console.log("relay RELAY_DONE final-reply semantics OK");

