// 雙失敗兜底：draft 過期 + placeholder 建立失敗 → 最後嘗試建 placeholder
if (!placeholder && !useDraftMode) {
  try {
    const msg = await ctx.api.sendMessage(chatId, "…",
      replyToId ? { reply_parameters: { message_id: replyToId } } : {});
    placeholder = msg;
    console.warn(`[chat ${chatId}] last-resort placeholder created for final delivery`);
  } catch (err) {
    console.error(`[chat ${chatId}] last-resort placeholder failed, switching to direct send`, err);
    // 連 placeholder 都建不了 → 走 useDraftMode path（sendRichMessage / sendMessage）
    useDraftMode = true;
  }
}
const chunks = splitForTelegram(full);
const pageTag = (i: number) =>
  chunks.length > 1 ? `(${i + 1}/${chunks.length})\n` : "";

const pace = () => new Promise<void>((r) => setTimeout(r, 1100));
let chunksSent = 0;
let chunksQueued = 0;
const sendOrQueue = async (text: string, extra?: Record<string, unknown>) => {
  try {
    const msg = await ctx.reply(text, extra);
    chunksSent++;
    return msg;
  } catch (err) {
    console.error(`[chat ${chatId}] chunk send failed, queueing for replay:`, err);
    queuePendingMessage(chatId, text);
    chunksQueued++;
    return undefined;
  }
};

